const raw = $input.first().json;
const body = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const isStructured = !!(body.clientName && body.firmName);
return [{ json: { ...body, _isStructured: isStructured, _inputText: body.message || body.text || body.input || '' } }];

const https = require('https');
const { execFileSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const os = require('os');
const d = $input.first().json;
console.log('DocGen: clientName=' + d.clientName);

async function getToken() {
  return new Promise((resolve, reject) => {
    const body = 'client_id=' + process.env.GRAPH_CLIENT_ID + '&client_secret=' + process.env.GRAPH_CLIENT_SECRET + '&scope=https%3A%2F%2Fgraph.microsoft.com%2F.default&grant_type=client_credentials';
    const req = https.request({ hostname: 'login.microsoftonline.com', path: '/' + process.env.GRAPH_TENANT_ID + '/oauth2/v2.0/token', method: 'POST', headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Content-Length': Buffer.byteLength(body) } }, res => { let data = ''; res.on('data', c => data += c); res.on('end', () => { try { resolve(JSON.parse(data).access_token); } catch(e) { reject(e); } }); });
    req.on('error', reject); req.write(body); req.end();
  });
}
async function downloadUrl(url) {
  return new Promise((resolve, reject) => {
    const follow = (u) => {
      const mod = u.startsWith('https') ? https : require('http');
      const parsed = require('url').parse(u);
      mod.get({ hostname: parsed.hostname, path: parsed.pathname + parsed.search, headers: {} }, res => {
        if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) { follow(res.headers.location); return; }
        const chunks = []; res.on('data', c => chunks.push(c)); res.on('end', () => resolve(Buffer.concat(chunks))); res.on('error', reject);
      }).on('error', reject);
    };
    follow(url);
  });
}
async function uploadToSharePoint(token, folderPath, fileName, buffer) {
  const sitePath = '/v1.0/sites/' + process.env.GRAPH_SITE_ID + '/drive/root:/';
  const uploadPath = sitePath + folderPath.replace(/ /g, '%20') + '/' + fileName.replace(/ /g, '%20') + ':/content';
  return new Promise((resolve, reject) => {
    const req = https.request({ hostname: 'graph.microsoft.com', path: uploadPath, method: 'PUT', headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', 'Content-Length': buffer.length } }, res => {
      let data = ''; res.on('data', c => data += c);
      res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve({ error: 'parse', raw: data.substring(0, 200) }); } });
    });
    req.on('error', reject); req.write(buffer); req.end();
  });
}

const token = await getToken();
const tplMeta = await new Promise((resolve, reject) => {
  https.get({ hostname: 'graph.microsoft.com', path: '/v1.0/sites/' + process.env.GRAPH_SITE_ID + '/drive/root:/DAX/Templates/Quarterly-Review-TEMPLATE.docx', headers: { 'Authorization': 'Bearer ' + token } }, res => {
    let data = ''; res.on('data', c => data += c); res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve({}); } });
  }).on('error', reject);
});
const dlUrl = tplMeta['@microsoft.graph.downloadUrl'];
if (!dlUrl) throw new Error('Template not found');
const tplBuffer = await downloadUrl(dlUrl);
if (tplBuffer.length < 1000) throw new Error('Template too small: ' + tplBuffer.length);

function dash(v) { return (v && String(v).trim()) ? String(v).trim() : '\u2014'; }
function esc(v) { return String(v||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

const templateData = {
  FIRM_NAME: d.firmName||'', CLIENT_NAME: d.clientName||'',
  REPORT_PERIOD: d.reportPeriod||'', REPORT_DATE: d.reportDate||'',
  ADVISOR_NAME: d.advisorName||'', ACCOUNT_NUMBER: d.accountNumber||'',
  ACCOUNT_TYPE: dash(d.accountType), RISK_PROFILE: dash(d.riskProfile),
  MEETING_DATE: d.meetingDate||'', MEETING_LOCATION: d.meetingLocation||'Zoom',
  ATTENDEES: d.attendees||'', MEETING_DURATION: d.meetingDuration||'',
  DISCUSSION_POINT_1: d.discussionPoint1||'', DISCUSSION_POINT_2: d.discussionPoint2||'', DISCUSSION_POINT_3: d.discussionPoint3||'',
  ADVISOR_NOTES: d.advisorNotes||'',
  PORTFOLIO_VALUE: d.portfolioValue||'', YTD_RETURN: d.ytdReturn||'',
  BENCHMARK_RETURN: d.benchmarkReturn||'', VS_BENCHMARK: d.vsBenchmark||'',
  TOP_HOLDING: dash(d.topHolding), INVESTMENT_OBJECTIVE: dash(d.investmentObjective),
  TIME_HORIZON: dash(d.timeHorizon), BACKGROUND_INFO: dash(d.backgroundInfo),
  GOALS_PROGRESS_NOTES: d.goalsProgressNotes||'',
  ACTION_1: d.action1||'', ACTION_1_OWNER: d.action1Owner||'', ACTION_1_DUE: d.action1Due||'',
  ACTION_2: d.action2||'', ACTION_2_OWNER: d.action2Owner||'', ACTION_2_DUE: d.action2Due||'',
  ACTION_3: d.action3||'', ACTION_3_OWNER: d.action3Owner||'', ACTION_3_DUE: d.action3Due||'',
  NEXT_MEETING_DATE: dash(d.nextMeetingDate), NEXT_MEETING_AGENDA: dash(d.nextMeetingAgenda),
  actions: [
    d.action1 ? { num: '1', text: d.action1, owner: d.action1Owner||'', due: d.action1Due||'TBD' } : null,
    d.action2 ? { num: '2', text: d.action2, owner: d.action2Owner||'', due: d.action2Due||'TBD' } : null,
    d.action3 ? { num: '3', text: d.action3, owner: d.action3Owner||'', due: d.action3Due||'TBD' } : null,
  ].filter(Boolean),
  discussions: [
    d.discussionPoint1 ? { num: '1', text: d.discussionPoint1 } : null,
    d.discussionPoint2 ? { num: '2', text: d.discussionPoint2 } : null,
    d.discussionPoint3 ? { num: '3', text: d.discussionPoint3 } : null,
  ].filter(Boolean),
  goals: [],
};
if (!templateData.actions.length) templateData.actions = [{ num: '1', text: 'No action items', owner: '', due: '' }];
if (!templateData.discussions.length) templateData.discussions = [{ num: '1', text: 'Discussion points to be covered' }];

// Run pizzip+docxtemplater in a subprocess to avoid n8n sandbox restrictions
const ts = Date.now();
const tmpDir = os.tmpdir();
const tplPath = path.join(tmpDir, 'dg-tpl-' + ts + '.docx');
const dataPath = path.join(tmpDir, 'dg-data-' + ts + '.json');
const scriptPath = path.join(tmpDir, 'dg-script-' + ts + '.js');

fs.writeFileSync(tplPath, tplBuffer);
fs.writeFileSync(dataPath, JSON.stringify(templateData));

const script = `
const PizZip = require('pizzip');
const Docxtemplater = require('docxtemplater');
const fs = require('fs');

const tplBuf = fs.readFileSync(process.argv[2]);
const data = JSON.parse(fs.readFileSync(process.argv[3], 'utf8'));

function esc(v) { return String(v||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

const zip = new PizZip(tplBuf);
const doc = new Docxtemplater(zip, {
  delimiters: { start: '{{', end: '}}' },
  paragraphLoop: true,
  linebreaks: true,
  nullGetter() { return ''; },
});
doc.render(data);
let docBuf = doc.getZip().generate({ type: 'nodebuffer', compression: 'DEFLATE' });

// Post-process: fix placeholders and white text
const zip2 = new PizZip(docBuf);
let xml = zip2.file('word/document.xml').asText();
xml = xml.split('Demo Advisor').join(esc(data.ADVISOR_NAME || 'Advisor'));
xml = xml.split('Impact Capital Partners').join(esc(data.FIRM_NAME || 'Impact Capital Partners'));
xml = xml.split('Key Discussion Points:').join('');
xml = xml.replace(/(\u003cw:color[^\u003e]+w:val=\")(?:FFFFFF|ffffff)(\")/g, '\$11F3864\$2');
zip2.file('word/document.xml', xml);
docBuf = zip2.generate({ type: 'nodebuffer', compression: 'DEFLATE' });

process.stdout.write(docBuf.toString('base64'));
`;
fs.writeFileSync(scriptPath, script);

let outputBase64;
try {
  outputBase64 = execFileSync('node', [scriptPath, tplPath, dataPath], {
    maxBuffer: 50 * 1024 * 1024,
    encoding: 'utf8',
    stdio: ['pipe', 'pipe', 'pipe'],
  });
  console.log('Doc generated: ' + outputBase64.length + ' base64 chars');
} catch (err) {
  if (err.stderr) console.log('Script error: ' + err.stderr.toString().substring(0, 300));
  throw new Error('Doc generation failed: ' + (err.stderr ? err.stderr.toString().substring(0,200) : err.message));
} finally {
  try { fs.unlinkSync(tplPath); } catch(_) {}
  try { fs.unlinkSync(dataPath); } catch(_) {}
  try { fs.unlinkSync(scriptPath); } catch(_) {}
}

const docBuffer = Buffer.from(outputBase64, 'base64');
const parts = (d.clientName||'Client').trim().split(' ');
const lastName = parts[parts.length-1];
const firstName = parts.slice(0,-1).join(' ');
const folderPath = 'DAX/Reports/' + lastName + ' - ' + firstName;
const cName = (d.clientName||'Report').replace(/[^a-zA-Z0-9 -]/g,'').trim();
const rPeriod = (d.reportPeriod||'Report').replace(/[^a-zA-Z0-9 -]/g,'').trim();
const dateStr = new Date().toISOString().split('T')[0];
const fileName = cName + ' - ' + rPeriod + ' (' + dateStr + ').docx';
console.log('Uploading: ' + folderPath + '/' + fileName);
const uploadResult = await uploadToSharePoint(token, folderPath, fileName, docBuffer);
if (uploadResult.error && !uploadResult.webUrl) throw new Error('Upload failed: ' + JSON.stringify(uploadResult));
return [{ json: { success: true, webUrl: uploadResult.webUrl||'', fileName: uploadResult.name||fileName, driveItemId: uploadResult.id||'', size: uploadResult.size||docBuffer.length, clientName: d.clientName, reportPeriod: d.reportPeriod } }];
